"""List large files (>1 MB) sorted by size descending."""

from pathlib import Path
from typing import List, Tuple
import argparse
import sys


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="List files larger than 1 MB in a directory tree."
    )
    parser.add_argument(
        "--dir",
        type=Path,
        default=Path("/tmp/output"),
        help="Directory to scan (default: /tmp/output)",
    )
    return parser.parse_args()


def find_large_files(directory: Path, min_size_mb: float = 1.0) -> List[Tuple[Path, int]]:
    """Return list of (path, size_bytes) for files >= min_size_mb MB."""
    size_threshold = int(min_size_mb * 1024 * 1024)
    large_files: List[Tuple[Path, int]] = []

    try:
        for path in directory.rglob("*"):
            try:
                if path.is_file():
                    size = path.stat().st_size
                    if size >= size_threshold:
                        large_files.append((path, size))
            except PermissionError:
                continue  # Skip files we can't stat
    except PermissionError as e:
        print(f"Permission denied scanning {e.filename}", file=sys.stderr)
        sys.exit(1)

    return large_files


def format_size(size_bytes: int) -> str:
    """Return human-readable size (MB)."""
    return f"{size_bytes / (1024 * 1024):.2f} MB"


def main() -> None:
    args = parse_args()

    if not args.dir.is_dir():
        print(f"Error: {args.dir} is not a directory", file=sys.stderr)
        sys.exit(1)

    large_files = find_large_files(args.dir)
    large_files.sort(key=lambda x: x[1], reverse=True)

    if not large_files:
        print(f"No files ≥ 1 MB found in {args.dir}")
        return

    print(f"Files ≥ 1 MB in {args.dir} (sorted by size descending):")
    for path, size in large_files:
        print(f"  {path} — {format_size(size)}")


if __name__ == "__main__":
