"""Resolve symlinks and classify entries in a directory."""

from pathlib import Path
import argparse


def classify_entries(root: Path) -> dict[str, list[Path]]:
    """Return categorized paths: symlinks, broken, regular files, directories."""
    results: dict[str, list[Path]] = {
        "symlinks": [],
        "broken": [],
        "regular_files": [],
        "directories": [],
    }

    try:
        for entry in root.iterdir():
            if entry.is_symlink():
                try:
                    resolved = entry.resolve(strict=False)
                    if resolved.exists():
                        results["symlinks"].append(entry)
                    else:
                        results["broken"].append(entry)
                except RuntimeError as e:
                    # Symlink loop detected
                    results["broken"].append(entry)
                    print(f"Warning: Symlink loop at {entry}: {e}", flush=True)
            elif entry.is_file():
                results["regular_files"].append(entry)
            elif entry.is_dir():
                results["directories"].append(entry)
    except PermissionError as e:
        print(f"Warning: Permission denied accessing {root}: {e}", flush=True)

    return results


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Classify path entries in a directory as symlinks, broken, or regular files."
    )
    parser.add_argument(
        "--root",
        type=Path,
        default=Path("/tmp/output"),
        help="Directory to scan (default: /tmp/output)",
    )
    args = parser.parse_args()

    if not args.root.exists():
        raise FileNotFoundError(f"Root path does not exist: {args.root}")
    if not args.root.is_dir():
        raise NotADirectoryError(f"Path is not a directory: {args.root}")

    results = classify_entries(args.root)

    print(f"Entries in {args.root}:")
    for category, paths in results.items():
        if paths:
            print(f"\n[{category}]")
            for p in paths:
                print(f"  {p}")


