#!/usr/bin/env python3
"""Safely delete .tmp files only under directories named 'staging'."""

import argparse
from pathlib import Path


def parse_args() -> argparse.Namespace:
    """Parse command-line arguments."""
    parser = argparse.ArgumentParser(
        description="Delete .tmp files only under directories containing 'staging'."
    )
    parser.add_argument(
        "--root",
        type=Path,
        default=Path("/tmp/output"),
        help="Root directory to search (default: /tmp/output)"
    )
    parser.add_argument(
        "--dry-run",
        action="store_true",
        help="Show what would be deleted without actually deleting"
    )
    return parser.parse_args()


def is_staging_dir(path: Path) -> bool:
    """Check if any parent directory name contains 'staging' (case-insensitive)."""
    return any("staging" in part.lower() for part in path.parts)


def delete_tmp_files(root: Path, dry_run: bool) -> int:
    """
    Walk bottom-up, delete .tmp files only if in staging-named path.
    Returns count of deleted files.
    """
    deleted_count = 0

    for dirpath, dirnames, filenames in root.walk(top_down=False):
        # Check if this dir or any parent contains 'staging'
        if not is_staging_dir(dirpath):
            continue

        for name in filenames:
            if name.lower().endswith(".tmp"):
                file_path = dirpath / name
                try:
                    if file_path.is_file():
                        if dry_run:
                            print(f"[DRY-RUN] Would delete: {file_path}")
                        else:
                            file_path.unlink()
                            print(f"Deleted: {file_path}", flush=True)
                        deleted_count += 1
                except PermissionError as e:
                    print(f"Permission denied: {file_path} — {e}", flush=True)

    return deleted_count


def main() -> None:
    """Main entry point."""
    args = parse_args()

    try:
        if not args.root.exists():
            raise FileNotFoundError(f"Root directory not found: {args.root}")

        if not args.dry_run:
            confirm = input(
                f"Delete .tmp files under staging directories in {args.root}? [y/N] "
            ).strip().lower()
            if confirm not in ("y", "yes"):
                print("Aborted.", flush=True)
                raise SystemExit(0)

        count = delete_tmp_files(args.root, args.dry_run)
        print(f"\nTotal .tmp files {'would be ' if args.dry_run else ''}deleted: {count}", flush=True)
    except FileNotFoundError as e:
        print(f"Error: {e}", flush=True)
        raise SystemExit(1) from e
    except KeyboardInterrupt:
        print("\nInterrupted.", flush=True)
        raise SystemExit(130) from None


if __name__ == "__main__":
    main()
