""" Safely rename .tmp files to .bak in /tmp/output using Path.replace(). """

from pathlib import Path
import argparse
import sys


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Rename .tmp files to .bak in a directory using Path.replace()."
    )
    parser.add_argument(
        "--input-dir",
        type=Path,
        default=Path("/tmp/output"),
        help="Directory to scan for .tmp files (default: /tmp/output)",
    )
    return parser.parse_args()


def rename_tmp_to_bak(input_dir: Path) -> None:
    """Rename .tmp files to .bak using Path.replace(), handling collisions gracefully."""
    try:
        tmp_files = list(input_dir.glob("*.tmp"))
    except PermissionError as e:
        print(f"Permission denied accessing {e.filename}", file=sys.stderr)
        sys.exit(1)

    for old_path in tmp_files:
        new_path = old_path.with_suffix(".bak")
        try:
            # replace() unconditionally overwrites existing files on all platforms
            new_path = old_path.replace(new_path)
            print(f"Renamed: {old_path.name} → {new_path.name}")
        except FileExistsError:
            print(f"Warning: {new_path} already exists; skipping {old_path.name}", file=sys.stderr)
        except PermissionError as e:
            print(f"Permission denied renaming {old_path}: {e.filename}", file=sys.stderr)
        except Exception as e:
            print(f"Error renaming {old_path}: {e}", file=sys.stderr)


def main() -> None:
    args = parse_args()
    input_dir = args.input_dir.expanduser().resolve()

    if not input_dir.is_dir():
        raise SystemExit(f"Error: {input_dir} is not a directory")

    if not list(input_dir.glob("*.tmp")):
        print("No .tmp files found.")
        return

    rename_tmp_to_bak(input_dir)


if __name__ == "__main__":
