""" Walk a directory tree and report symlinks with their targets. """

from pathlib import Path
import argparse


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Recursively walk directory and report symlinks and their targets."
    )
    parser.add_argument(
        "--root",
        type=Path,
        default=Path("/tmp/output"),
        help="Root directory to walk (default: /tmp/output)",
    )
    return parser.parse_args()


def report_symlinks(root: Path) -> None:
    """Walk root and print symlinks with their targets."""
    try:
        for dirpath, dirnames, filenames in root.walk(follow_symlinks=False):
            path_dir = Path(dirpath)

            # Check directories for symlinks (not actual dirs)
            for dirname in dirnames[:]:  # slice copy to allow mutation
                dir_path = path_dir / dirname
                if dir_path.is_symlink():
                    try:
                        target = dir_path.readlink()
                        print(f"Directory symlink: {dir_path} → {target}")
                    except OSError as e:
                        print(f"Error reading symlink {dir_path}: {e}", flush=True)

            # Check files for symlinks
            for filename in filenames:
                file_path = path_dir / filename
                if file_path.is_symlink():
                    try:
                        target = file_path.readlink()
                        print(f"File symlink: {file_path} → {target}")
                    except OSError as e:
                        print(f"Error reading symlink {file_path}: {e}", flush=True)
    except PermissionError as e:
        print(f"Permission denied accessing {e.filename}", flush=True)
    except FileNotFoundError as e:
        print(f"Path not found: {e.filename}", flush=True)


def main() -> None:
    args = parse_args()
    root = args.root.expanduser().resolve()

    if not root.is_dir():
        raise SystemExit(f"Error: {root} is not a directory")

    report_symlinks(root)


if __name__ == "__main__":
