        type=int,
        default=1_048_576,  # 1 MB
        help="Minimum file size in bytes (default: 1 MB = 1_048_576)"
    )
    return parser.parse_args()


def list_large_files(directory: Path, min_size: int) -> list[Path]:
    """Return list of files ≥ min_size in bytes. Non-recursive."""
    if not directory.exists():
        raise FileNotFoundError(f"Directory not found: {directory}")
    if not directory.is_dir():
        raise NotADirectoryError(f"Path is not a directory: {directory}")

    large_files: list[Path] = []

    try:
        for entry in directory.iterdir():
            if entry.is_file():
                try:
                    if entry.stat().st_size >= min_size:
                        large_files.append(entry)
                except PermissionError:
                    print(f"Skipped (permission denied): {entry}", file=sys.stderr)
    except PermissionError as e:
        raise PermissionError(f"Cannot read directory {directory}: {e}") from e

    return large_files


