#!/usr/bin/env python3
"""List directories with zero files (ignoring subdirectories)."""

from pathlib import Path
from argparse import ArgumentParser
from collections import Counter
from typing import Set, Tuple


def list_all_dirs(root: Path) -> Set[Path]:
    """Return set of all directories under root."""
    return {p for p in root.rglob('*') if p.is_dir()}


def get_files_in_dir(dir_path: Path) -> list[Path]:
    """Return list of files directly inside dir_path (not recursive)."""
    try:
        return [p for p in dir_path.iterdir() if p.is_file()]
    except PermissionError:
        return []


def find_empty_dirs(root: Path) -> list[Path]:
    """Return list of directories containing zero files (non-recursive file check)."""
    empty_dirs: list[Path] = []
    for d in list_all_dirs(root):
        files = get_files_in_dir(d)
        if not files:
            empty_dirs.append(d)
    return empty_dirs


def validate_with_counter(dirs: list[Path]) -> None:
    """Validate uniqueness and print stats using Counter."""
    counter: Counter = Counter()
    for d in dirs:
        counter[ str(d.resolve()) ] += 1

    duplicates = sum(count > 1 for count in counter.values())
    if duplicates > 0:
        print(f"Warning: Found {duplicates} duplicate paths in result.")
    else:
        print(f"Validation passed: {len(dirs)} unique empty directories found.")


def main() -> None:
    parser = ArgumentParser(
        description='List directories with no files (non-recursive file check).'
    )
    parser.add_argument(
        'directory',
        type=Path,
        help='Root directory to scan (e.g., /mnt/agency-docs)'
    )
