    if not args.directory.is_dir():
        raise NotADirectoryError(f"Path is not a directory: {args.directory}")

    empty = find_empty_dirs(args.directory)

    if not empty:
        print("No directories with zero files found.")
    else:
        print(f"Found {len(empty)} directories with no files:")
        for d in sorted(empty):
            print(f"  {d.relative_to(args.directory)}")

    if args.validate:
        validate_with_counter(empty)


if __name__ == '__main__':
    main()
