#!/usr/bin/env python3
"""Move .txt files from source directories to an archive directory."""

from pathlib import Path
from argparse import ArgumentParser
from typing import List


def find_txt_files(directories: List[Path]) -> List[Path]:
    """Return all .txt files in the given directories (non-recursive)."""
    txt_files: List[Path] = []
    for directory in directories:
        if not directory.exists():
            raise FileNotFoundError(f"Directory not found: {directory}")
        if not directory.is_dir():
            raise ValueError(f"Path is not a directory: {directory}")
        txt_files.extend(directory.glob('*.txt'))
    return sorted(txt_files)


def move_to_archive(
    files: List[Path],
    archive_dir: Path,
    dry_run: bool = False
) -> int:
    """Move files to archive_dir, handling name collisions. Returns count moved."""
    archive_dir.mkdir(parents=True, exist_ok=True)
    moved = 0

    for src in files:
        dest = archive_dir / src.name

        # Handle rename collisions: append timestamp if needed
        if dest.exists():
            stem = src.stem
            suffix = src.suffix
            timestamp = src.stat().st_mtime
            dest = archive_dir / f"{stem}_{int(timestamp)}{suffix}"

        try:
            if dry_run:
                print(f"[DRY-RUN] Would move: {src} → {dest}")
            else:
                src.rename(dest)
                print(f"Moved: {src} → {dest}")
            moved += 1
        except FileExistsError:
            print(f"ERROR: Could not move {src} — collision at {dest}")
        except PermissionError as e:
            print(f"ERROR: Permission denied moving {src}: {e.filename or 'unknown'}")
        except Exception as e:
            print(f"ERROR: Failed to move {src}: {e}")

    return moved


def main() -> None:
    parser = ArgumentParser(
        description="Move .txt files from source dirs to archive directory."
    )
    parser.add_argument(
        'sources',
        type=Path,
        nargs='+',
        help="Source directories to scan for .txt files"
    )
    parser.add_argument(
        '-a', '--archive',
        type=Path,
        default=Path('/tmp/output/archive'),
        help="Archive destination (default: /tmp/output/archive)"
    )
    parser.add_argument(
        '--dry-run',
        action='store_true',
        help="Show what would happen without moving files"
    )

    args = parser.parse_args()

    try:
        txt_files = find_txt_files(args.sources)
    except (FileNotFoundError, ValueError) as e:
        parser.error(str(e))

    if not txt_files:
        print("No .txt files found in source directories.")
        return

    print(f"Found {len(txt_files)} .txt file(s) to move.")
    moved = move_to_archive(txt_files, args.archive, args.dry_run)

    if not args.dry_run:
        print(f"Moved {moved} file(s).")
    else:
        print("[DRY-RUN] No files were moved.")


if __name__ == '__main__':
    main()
```

