        type=Path,
        default=Path("/tmp/output/manifest.txt"),
        help="Path to manifest file listing file paths (default: /tmp/output/manifest.txt)",
    )
    return parser.parse_args()


def read_manifest(manifest_path: Path) -> List[str]:
