    except FileNotFoundError:
        print(f"Manifest file not found: {manifest_path}", file=sys.stderr)
        sys.exit(1)
    except PermissionError:
        print(f"Permission denied reading manifest: {manifest_path}", file=sys.stderr)
        sys.exit(2)


def verify_files(paths: List[str]) -> Tuple[List[Path], List[Tuple[str, str]]]:
    """Verify each path exists and is a file. Return (valid, [(path, error)])."""
    valid: List[Path] = []
    errors: List[Tuple[str, str]] = []

    for path_str in paths:
        p = Path(path_str)
        try:
            if not p.exists():
                errors.append((path_str, "File not found"))
            elif not p.is_file():
                errors.append((path_str, "Not a regular file"))
            else:
                valid.append(p)
        except PermissionError:
            errors.append((path_str, "Permission denied"))
        except OSError as e:
            errors.append((path_str, f"OS error: {e}"))

    return valid, errors


def main() -> None:
