#!/usr/bin/env python3
"""List all files in a directory, handling permission errors gracefully."""

from pathlib import Path
import argparse
import sys
from typing import Iterator, Tuple

def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="List files in a directory with permission-error resilience"
    )
    parser.add_argument(
        "--input-dir",
        type=Path,
        default=Path("/tmp/output"),
        help="Directory to scan (default: /tmp/output)"
    )
    parser.add_argument(
        "--no-recursive",
        action="store_true",
        help="Only list top-level entries (default: recursive)"
    )
    return parser.parse_args()

def list_entries(path: Path, recursive: bool = True) -> Iterator[Tuple[Path, str]]:
    """Yield (path, status) tuples for all entries, handling errors."""
    try:
        # Get entries
        entries = path.iterdir() if recursive else [path]

        for entry in entries:
            if entry.is_file():
                yield entry, "file"
            elif entry.is_dir():
                if recursive:
                    # Recurse with error handling
                    try:
                        yield from list_entries(entry, recursive=True)
                    except PermissionError:
                        yield entry, "permission_denied"
                else:
                    yield entry, "directory"
            else:
                yield entry, "other"

    except PermissionError:
        # If parent directory can't be read
        yield path, "permission_denied"
    except OSError as e:
        yield path, f"os_error: {e.errno}"

def main() -> int:
    args = parse_args()

    if not args.input_dir.exists():
        print(f"Error: Directory not found: {args.input_dir}", file=sys.stderr)
        return 1
    if not args.input_dir.is_dir():
        print(f"Error: Path is not a directory: {args.input_dir}", file=sys.stderr)
        return 1

    print(f"Scanning: {args.input_dir}")

    try:
        for path, status in list_entries(args.input_dir, recursive=not args.no_recursive):
            if status == "permission_denied":
                print(f"[DENIED] {path}")
            elif status == "os_error":
                print(f"[OS ERROR] {path}")
            else:
                print(f"[{status.upper():8}] {path}")

        return 0

    except Exception as e:
        print(f"Unexpected error: {e}", file=sys.stderr)
        return 3

if __name__ == "__main__":
    sys.exit(main())
```

Key features:
- Uses `path.iterdir()` (not `glob()` or `rglob()`) for direct directory iteration
- Recursive by default, with `--no-recursive` to list only top-level items
- `PermissionError` caught per-directory; scanning continues where possible
- Returns `(Path, status)` tuples with type hints
- Outputs `[FILE]`, `[DIRECTORY]`, `[DENIED]`, etc. for clear status
- Handles `OSError` variants gracefully
- Full `argparse` integration with `--help`

