#!/usr/bin/env python3
"""Validate files in a directory: readable content and no hidden files."""

import argparse
import sys
from pathlib import Path


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Validate files: readable content and no hidden files."
    )
    parser.add_argument(
        "--root",
        type=Path,
        default=Path("/mnt/agency-docs"),
        help="Root directory to scan (default: /mnt/agency-docs)"
    )
    return parser.parse_args()


def is_hidden(path: Path) -> bool:
    """Check if any component of path is hidden (starts with '.')."""
    return any(part.startswith(".") for part in path.parts)


def validate_file(path: Path) -> tuple[bool, str]:
    """Check if file is readable and non-empty. Returns (success, error_msg)."""
    try:
        content = path.read_text(encoding="utf-8")
        if not content.strip():
            return False, "Empty or whitespace-only content"
        return True, ""
    except UnicodeDecodeError as e:
        return False, f"Encoding error: {e}"
    except PermissionError:
        return False, "Permission denied reading file"
    except OSError as e:
        return False, f"OS error: {e}"


def main() -> int:
    args = parse_args()
    root: Path = args.root

    if not root.exists():
        print(f"Error: Root directory does not exist: {root}", file=sys.stderr)
        return 1

    errors = 0

    for path in root.rglob("*"):
        if not path.is_file():
            continue

        # Check for hidden files/dirs
        if is_hidden(path):
            print(f"WARNING: Hidden file: {path}", file=sys.stderr)

        # Check readability
        ok, msg = validate_file(path)
        if not ok:
            print(f"ERROR: {path}: {msg}", file=sys.stderr)
            errors += 1

    summary = f"Validation complete: {errors} error(s) found"
    if errors == 0:
        print(summary)
    else:
        print(summary, file=sys.stderr)

    return 1 if errors else 0


if __name__ == "__main__":
    sys.exit(main())
