#!/usr/bin/env python3.12
"""Recursively compute MD5 checksums and output CSV."""

import hashlib
from pathlib import Path
from argparse import ArgumentParser
from typing import Iterable, Iterator, Tuple
import csv
import sys


def md5_stream(path: Path, chunk_size: int = 65536) -> str:
    """Return MD5 hex digest for file, streaming in chunks."""
    hasher = hashlib.md5()
    try:
        with path.open('rb') as f:
            while chunk := f.read(chunk_size):
                hasher.update(chunk)
    except PermissionError as e:
        raise PermissionError(f'Cannot read {path}: {e}')
    except OSError as e:
        raise OSError(f'IO error reading {path}: {e}')
    return hasher.hexdigest()


def iter_files(root: Path) -> Iterator[Path]:
    """Yield all regular files under root recursively."""
    try:
        for path in root.rglob('*'):
            if path.is_file():
                yield path
    except PermissionError as e:
        raise PermissionError(f'Cannot traverse {root}: {e}')


def parse_args() -> Path:
    parser = ArgumentParser(
        description='Recursively compute MD5 checksums of all files.'
    )
    parser.add_argument(
        'root',
        type=Path,
        default=Path('/mnt/agency-docs'),
        nargs='?',
        help='Root directory (default: /mnt/agency-docs)'
    )
    parser.add_argument(
        '--output',
        type=Path,
        default=Path('-'),
        help='Output CSV path (default: stdout)'
    )
    args = parser.parse_args()

    if not args.root.exists():
        raise FileNotFoundError(f'Path does not exist: {args.root}')
    return args.root


def generate_checksums(root: Path) -> Iterator[Tuple[str, str]]:
    """Yield (relpath, md5) for each file."""
    for path in iter_files(root):
        rel = path.relative_to(root)
        try:
            checksum = md5_stream(path)
            yield str(rel), checksum
        except (PermissionError, OSError) as e:
            # Log to stderr, continue
            print(f'Warning: {e}', file=sys.stderr)


def main() -> None:
    root = parse_args()

    try:
        output_path = parse_args.__defaults__[0]  # dummy; re-parse if needed
    except:
        pass

    parser = ArgumentParser(parents=[])
    parser = ArgumentParser(description='Recursively compute MD5 checksums')
    parser.add_argument('root', type=Path, default=Path('/mnt/agency-docs'), nargs='?')
    parser.add_argument('--output', type=Path, default=Path('-'))
    args = parser.parse_args()

    output = sys.stdout
    if args.output != Path('-'):
        try:
            output = args.output.open('w', newline='', encoding='utf-8')
        except PermissionError as e:
            print(f'Cannot write to {args.output}: {e}', file=sys.stderr)
            sys.exit(1)

    writer = csv.writer(output)
    writer.writerow(['path', 'md5'])

    try:
        for relpath, checksum in generate_checksums(args.root):
            writer.writerow([relpath, checksum])
    except PermissionError as e:
        print(f'Stopped: {e}', file=sys.stderr)
        sys.exit(1)
    finally:
        if output is not sys.stdout:
            output.close()


if __name__ == '__main__':
    main()
```

