#!/usr/bin/env python3.12
"""Find duplicate files by SHA-256 hash and group them."""

from pathlib import Path
from collections import Counter
from hashlib import sha256
import argparse
import sys


def hash_file(path: Path, block_size: int = 65536) -> str:
    """Compute SHA-256 hash of a file in chunks."""
    h = sha256()
    try:
        with path.open('rb') as f:
            for chunk in iter(lambda: f.read(block_size), b''):
                h.update(chunk)
        return h.hexdigest()
    except FileNotFoundError:
        raise FileNotFoundError(f"File disappeared during hashing: {path}")
    except PermissionError as e:
        raise PermissionError(f"Cannot read {path}: {e}")


def group_files_by_hash(directory: Path) -> dict[str, list[Path]]:
    """Return dict mapping hash → list of files with that hash."""
    hash_to_files: dict[str, list[Path]] = {}

    if not directory.is_dir():
        raise NotADirectoryError(f"{directory} is not a directory")

    for path in directory.iterdir():
        if path.is_file():
            try:
                file_hash = hash_file(path)
                hash_to_files.setdefault(file_hash, []).append(path)
            except (FileNotFoundError, PermissionError) as e:
                print(f"⚠️  Skipping {path}: {e}", file=sys.stderr)

    return hash_to_files


def main() -> None:
    parser = argparse.ArgumentParser(
        prog='find_duplicates',
        description='Group files by content hash (SHA-256) in a directory.'
    )
    parser.add_argument(
        'directory',
        type=Path,
        default=Path('/tmp/output'),
        nargs='?',
        help='Directory to scan (default: /tmp/output)'
    )

    args = parser.parse_args()

    if not args.directory.exists():
        print(f"❌ Directory does not exist: {args.directory}", file=sys.stderr)
        sys.exit(1)

    groups = group_files_by_hash(args.directory)

    # Filter to only groups with >1 file (i.e., duplicates)
    duplicates = {h: paths for h, paths in groups.items() if len(paths) > 1}

    if not duplicates:
        print("✅ No duplicate files found.")
        return

    print(f"\nFound {len(duplicates)} groups of duplicate files:\n")

    for i, (file_hash, paths) in enumerate(duplicates.items(), 1):
        print(f"Group {i} (hash: {file_hash[:16]}…):")
        for path in sorted(paths):
            print(f"  • {path}")
        print()


if __name__ == '__main__':
    main()
```

