#!/usr/bin/env python3.12
"""Count files by extension in a directory tree."""

import argparse
import sys
from collections import Counter
from pathlib import Path
from typing import NoReturn


def count_extensions(path: Path) -> Counter[str]:
    """Return a Counter of file extensions (lowercase, no dot) under path."""
    if not path.exists():
        raise FileNotFoundError(f"Path does not exist: {path}")
    if not path.is_dir():
        raise NotADirectoryError(f"Path is not a directory: {path}")

    extensions: list[str] = []
    for item in path.rglob('*'):
        if item.is_file():
            ext = item.suffix.lstrip('.').lower()
            if ext:  # skip files without extension
                extensions.append(ext)
            else:
                extensions.append('no-extension')

    return Counter(extensions)


def parse_args(args: list[str] | None = None) -> argparse.Namespace:
    """Parse command-line arguments."""
    parser = argparse.ArgumentParser(
        description='Count files by extension in a directory tree.',
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog='Example: python count_ext.py --path /mnt/agency-docs --output counts.json',
    )
    parser.add_argument(
        '--path',
        type=Path,
        default=Path('/mnt/agency-docs'),
        help='Root directory to scan (default: /mnt/agency-docs)',
    )
    parser.add_argument(
        '--output',
        type=Path,
        default=None,
        help='Optional output file path (default: print to stdout)',
    )
    return parser.parse_args(args)


def main() -> NoReturn:
    """Main entrypoint."""
    try:
        args = parse_args()
        counts = count_extensions(args.path)

        # Sort by frequency descending, then alphabetically
        sorted_items = sorted(
            counts.items(),
            key=lambda x: (-x[1], x[0]),
        )

        output_lines = ['Extension,Count']
        for ext, cnt in sorted_items:
            output_lines.append(f'{ext},{cnt}')

        output_text = '\n'.join(output_lines)

        if args.output:
            try:
                args.output.write_text(output_text)
            except PermissionError:
                print(f"Error: Cannot write to {args.output} — permission denied.", file=sys.stderr)
                sys.exit(1)
        else:
            print(output_text)

    except FileNotFoundError as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(2)
    except NotADirectoryError as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(3)
    except PermissionError:
        print("Error: Access denied while reading directory.", file=sys.stderr)
        sys.exit(3)


if __name__ == '__main__':
    main()
```

