#!/usr/bin/env python3.12
"""Find duplicate files by content hash."""

import argparse
import hashlib
import sys
from collections import defaultdict
from pathlib import Path
from typing import NoReturn


CHUNK_SIZE = 65536  # 64 KiB chunks for streaming reads
HASH_ALGO = hashlib.blake2b


def hash_file(filepath: Path) -> str:
    """Return hex digest of filepath using blake2b."""
    with filepath.open('rb') as f:
        digest = HASH_ALGO()
        while chunk := f.read(CHUNK_SIZE):
            digest.update(chunk)
        return digest.hexdigest()


def find_duplicates(root: Path) -> dict[str, list[Path]]:
    """Return mapping: hash -> list of files with that hash."""
    if not root.exists() or not root.is_dir():
        raise ValueError(f"Invalid directory: {root}")

    size_map: dict[int, list[Path]] = defaultdict(list)

    # Group by size first (fast filter)
    for path in root.rglob('*'):
        if path.is_file():
            try:
                size_map[path.stat().st_size].append(path)
            except PermissionError:
                print(f"Warning: Skipping unreadable file: {path}", file=sys.stderr)
                continue

    # Only hash files that share a size
    hash_map: dict[str, list[Path]] = defaultdict(list)
    for size, files in size_map.items():
        if len(files) < 2:
            continue
        for file in files:
            try:
                file_hash = hash_file(file)
                hash_map[file_hash].append(file)
            except PermissionError:
                print(f"Warning: Cannot hash file: {file}", file=sys.stderr)
                continue

    return {h: files for h, files in hash_map.items() if len(files) > 1}


def parse_args(args: list[str] | None = None) -> argparse.Namespace:
    """Parse CLI arguments."""
    parser = argparse.ArgumentParser(
        description='Find duplicate files by content hash (blake2b).',
    )
    parser.add_argument(
        '--path',
        type=Path,
        default=Path('/mnt/agency-docs'),
        help='Root directory to scan (default: /mnt/agency-docs)',
    )
    parser.add_argument(
        '--quiet',
        action='store_true',
        help='Suppress warnings (e.g., permission errors)',
    )
    return parser.parse_args(args)


def main() -> NoReturn:
    """Entry point."""
    args = parse_args()
    duplicates = find_duplicates(args.path)

    if not duplicates:
        print("No duplicates found.")
        sys.exit(0)

    for h, files in duplicates.items():
        print(f"\nHash: {h[:16]}… ({len(files)} files)")
        for f in files:
            print(f"  {f}")

    print(f"\nTotal unique duplicates: {len(duplicates)}")
    sys.exit(0)


if __name__ == '__main__':
    main()
```

**Key points:**
- Uses `pathlib.Path.rglob('*')` and `hashlib.blake2b`
- Two-pass: size grouping → hash only for candidates (efficiency)
- Graceful permission error handling with warnings to stderr
- `--quiet` flag suppresses warnings
- Fully typed, `--help` enabled

