```python
#!/usr/bin/env python3
"""List the N largest files in a directory tree."""
import argparse
import heapq
import sys
from pathlib import Path
from typing import List, Tuple


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Find the N largest files in a directory tree."
    )
    parser.add_argument(
        "--input-dir",
        type=Path,
        default=Path("/mnt/agency-docs"),
        help="Root directory to scan (default: /mnt/agency-docs)",
    )
    parser.add_argument(
        "--n",
        type=int,
        default=5,
        help="Number of largest files to list (default: 5)",
    )
    return parser.parse_args()


def get_file_sizes(root: Path, top_n: int = 5) -> List[Tuple[int, Path]]:
    """Return list of (size, path) tuples for top N largest files."""
    # Min-heap of size n: (size, path)
    heap: List[Tuple[int, Path]] = []

    try:
        for path in root.rglob("*"):
            try:
                if path.is_file():
                    size = path.stat().st_size
                    if len(heap) < top_n:
                        heapq.heappush(heap, (size, path))
                    elif size > heap[0][0]:
                        heapq.heapreplace(heap, (size, path))
            except PermissionError:
                print(f"Warning: Permission denied accessing {path}. Skipping…", file=sys.stderr)
                continue
            except OSError as e:
                print(f"Warning: Could not stat {path}: {e}. Skipping…", file=sys.stderr)
                continue
    except PermissionError as e:
        print(f"Error: Permission denied scanning root: {e.filename}", file=sys.stderr)
        sys.exit(1)
    except FileNotFoundError as e:
        print(f"Error: Directory not found: {e.filename}", file=sys.stderr)
        sys.exit(1)

    # Sort descending by size
    return sorted(heap, key=lambda x: x[0], reverse=True)


def main() -> None:
    args = parse_args()

    if not args.input_dir.is_dir():
        print(f"Error: Path is not a directory: {args.input_dir}", file=sys.stderr)
        sys.exit(1)

    top_files = get_file_sizes(args.input_dir, args.n)

    if not top_files:
        print("No files found.")
        return

    print(f"Top {len(top_files)} largest files in {args.input_dir}:")
    for size, path in top_files:
        print(f"{size:>12} bytes  {path}")


if __name__ == "__main__":
    main()
```

✅ Key features:
- `rglob("*")` + `is_file()` avoids following symlinks inadvertently
- `heapq` for O(log N) updates — scales better than sorting all files
- `PermissionError` and `OSError` caught per-file and per-directory
- Clear exit codes and user-friendly stderr messages
- Uses `pathlib.Path.stat().st_size` (no `os.path`)

Run: `python3 largest-files.py --help`

