"""Report directories with more than 5 files in a given tree."""

from pathlib import Path
import argparse
import sys


def parse_args() -> argparse.Namespace:
    """Parse command-line arguments."""
    parser = argparse.ArgumentParser(
        description="Report directories containing more than 5 files."
    )
    parser.add_argument(
        "--input-dir",
        type=Path,
        default=Path("/tmp/output"),
        help="Root directory to scan (default: /tmp/output)"
    )
    parser.add_argument(
        "--threshold",
        type=int,
        default=5,
        help="Minimum file count to report (default: 5)"
    )
    return parser.parse_args()


def directories_with_many_files(root: Path, threshold: int) -> list[tuple[Path, int]]:
    """Yield (dir, count) for directories containing >threshold files."""
    try:
        for dirpath in root.rglob("*"):
            if not dirpath.is_dir():
                continue
            try:
                file_count = sum(1 for p in dirpath.iterdir() if p.is_file())
            except PermissionError:
                continue
            if file_count > threshold:
                yield dirpath, file_count
    except PermissionError:
        print(f"Permission denied: {root}", file=sys.stderr)
        return


def main() -> None:
    """Main entry point."""
    args = parse_args()

    if not args.input_dir.exists():
        print(f"Error: Input directory does not exist: {args.input_dir}", file=sys.stderr)
        sys.exit(1)

    if not args.input_dir.is_dir():
        print(f"Error: Input path is not a directory: {args.input_dir}", file=sys.stderr)
        sys.exit(1)

    results = list(directories_with_many_files(args.input_dir, args.threshold))

    if not results:
        print(f"No directories found with more than {args.threshold} files.")
        return

    print(f"Directories with >{args.threshold} files:")
    for dirpath, count in sorted(results, key=lambda x: x[1], reverse=True):
        print(f"  {dirpath}: {count} files")


if __name__ == "__main__":
