Here's a robust duplicate-finder script using `pathlib.Path`, `hashlib.sha256`, `collections.defaultdict`, and `argparse`. It includes error handling, type hints, and a clean CLI.

```python
#!/usr/bin/env python3
"""Scan directory for duplicate files by SHA-256 hash and group them."""

from pathlib import Path
from collections import defaultdict
from hashlib import sha256
import argparse
import sys
from typing import Dict, List, Set

CHUNK_SIZE = 65536  # 64 KB chunks for memory efficiency


def compute_hash(path: Path) -> str:
    """Compute SHA-256 hash of a file using streaming (safe for large files)."""
    h = sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(CHUNK_SIZE), b""):
            h.update(chunk)
    return h.hexdigest()


def find_duplicates(root: Path, *, verbose: bool = False) -> Dict[str, List[Path]]:
    """Return dict mapping hash → list of paths (only non-unique hashes included)."""
    hash_to_paths: Dict[str, List[Path]] = defaultdict(list)
    errors: Set[str] = set()

    try:
        for path in root.rglob("*"):
            if path.is_file():
                try:
                    file_hash = compute_hash(path)
                    hash_to_paths[file_hash].append(path)
                except PermissionError:
                    errors.add(str(path))
                except OSError as e:
                    if verbose:
                        print(f"Warning: Could not read {path}: {e}", file=sys.stderr)
                    errors.add(str(path))

    except PermissionError as e:
        print(f"Permission denied accessing root directory: {e}", file=sys.stderr)
        sys.exit(2)

    if verbose and errors:
        print(f"Skipped {len(errors)} file(s) due to access errors.", file=sys.stderr)

    # Keep only groups with duplicates (size > 1)
    return {h: paths for h, paths in hash_to_paths.items() if len(paths) > 1}


def main():
    parser = argparse.ArgumentParser(
        description="Find duplicate files in a directory tree by SHA-256 hash."
    )
    parser.add_argument(
        "directory",
        type=Path,
        help="Root directory to scan (e.g., /tmp/output)"
    )
    parser.add_argument(
        "--verbose",
        action="store_true",
        help="Output skipped files and diagnostic info"
    )
    parser.add_argument(
        "--output",
        type=Path,
        help="Write report to this file (default: stdout)"
    )

    args = parser.parse_args()

    root: Path = args.directory

    # Validate root
    try:
        if not root.exists():
            raise FileNotFoundError(f"Directory not found: {root}")
        if not root.is_dir():
            raise NotADirectoryError(f"Not a directory: {root}")
    except (FileNotFoundError, NotADirectoryError) as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

    duplicates = find_duplicates(root, verbose=args.verbose)

    output_lines = [f"Found {len(duplicates)} group(s) of duplicate files:"]

    if not duplicates:
        output_lines.append("No duplicates found.")
    else:
        for i, (hash_, paths) in enumerate(duplicates.items(), start=1):
            output_lines.append(f"\nGroup {i} (hash: {hash_[:16]}…):")
            for p in paths:
                output_lines.append(f"  {p}")
            output_lines.append(f"  → {len(paths)} files ({paths[0].stat().st_size} bytes each)")

    report = "\n".join(output_lines)

    if args.output:
        try:
            args.output.write_text(report + "\n")
            if args.verbose:
                print(f"Report saved to {args.output}", file=sys.stderr)
        except PermissionError:
            print(f"Error: Cannot write to {args.output} (permission denied)", file=sys.stderr)
            sys.exit(3)
    else:
        print(report)


if __name__ == "__main__":
    main()
```

