#!/usr/bin/env python3
"""Find duplicate PDF filenames recursively in a directory tree."""

import argparse
import sys
from collections import Counter
from pathlib import Path


def parse_args() -> argparse.Namespace:
    """Parse and validate command-line arguments."""
    parser = argparse.ArgumentParser(
        description="Find duplicate PDF files by filename in a directory tree."
    )
    parser.add_argument(
        "--input-dir",
        type=Path,
        default=Path("/mnt/agency-docs"),
        help="Root directory to search (default: /mnt/agency-docs)",
    )
    return parser.parse_args()


def find_pdf_files(root: Path) -> list[Path]:
    """Recursively find all .pdf files under root."""
    return list(root.rglob("*.pdf"))


def group_by_filename(files: list[Path]) -> dict[str, list[Path]]:
    """Group files by their filename, ignoring path."""
    counter: Counter[str] = Counter(f.name for f in files)
    duplicates = {name for name, count in counter.items() if count > 1}
    grouped: dict[str, list[Path]] = {}
    for file_path in files:
        name = file_path.name
        if name in duplicates:
            grouped.setdefault(name, []).append(file_path)
    return grouped


def main() -> None:
    args = parse_args()
    if not args.input_dir.is_dir():
        print(f"Error: {args.input_dir} is not a valid directory", file=sys.stderr)
        sys.exit(1)

    files = find_pdf_files(args.input_dir)
    duplicates = group_by_filename(files)

    if not duplicates:
        print("No duplicate PDF filenames found.")
        return

    print("Duplicate PDF files by filename:")
    for filename, paths in sorted(duplicates.items()):
        print(f"\n{filename}:")
        for path in sorted(paths):
            print(f"  - {path}")


if __name__ == "__main__":
    main()
