#!/usr/bin/env python3
"""Summarize file system objects in a directory tree using pathlib."""

import argparse
import sys
from pathlib import Path


def parse_args() -> argparse.Namespace:
    """Parse and validate command-line arguments."""
    parser = argparse.ArgumentParser(
        description="Count files, directories, and symlinks in a directory tree."
    )
    parser.add_argument(
        "--input-dir",
        type=Path,
        default=Path("/tmp/output"),
        help="Root directory to analyze (default: /tmp/output)",
    )
    return parser.parse_args()


def count_objects(root: Path) -> tuple[int, int, int, list[str]]:
    """
    Count files, directories, symlinks under root.
    Returns (file_count, dir_count, symlink_count, errors).
    """
    files = dirs = symlinks = 0
    errors: list[str] = []

    try:
        for entry in root.rglob("*"):
            try:
                if entry.is_symlink():
                    symlinks += 1
                elif entry.is_dir():
                    dirs += 1
                elif entry.is_file():
                    files += 1
            except PermissionError as e:
                errors.append(f"Permission denied: {entry}")
            except OSError as e:
                errors.append(f"OS error for {entry}: {e}")
    except PermissionError as e:
        errors.append(f"Permission denied accessing root: {root}")
    except FileNotFoundError as e:
        errors.append(f"Directory not found: {root}")

    return files, dirs, symlinks, errors


def main() -> None:
    args = parse_args()

    if not args.input_dir.exists():
        print(f"Error: Path {args.input_dir} does not exist.", file=sys.stderr)
        sys.exit(1)

    files, dirs, symlinks, errors = count_objects(args.input_dir)

    print(f"Summary for {args.input_dir}:")
    print(f"  Regular files: {files}")
    print(f"  Directories:   {dirs}")
    print(f"  Symlinks:      {symlinks}")

    if errors:
        print("\nErrors encountered:")
        for err in errors:
            print(f"  - {err}")


if __name__ == "__main__":
    main()
