#!/usr/bin/env python3
"""Recursively copy .txt files from source to destination preserving structure."""

import argparse
import shutil
import sys
from pathlib import Path


def parse_args() -> argparse.Namespace:
    """Parse and validate command-line arguments."""
    parser = argparse.ArgumentParser(
        description="Copy .txt files from source to destination preserving directory structure."
    )
    parser.add_argument(
        "--source",
        type=Path,
        required=True,
        help="Source directory (e.g., /mnt/agency-docs)",
    )
    parser.add_argument(
        "--destination",
        type=Path,
        required=True,
        help="Destination directory (e.g., /tmp/output)",
    )
    return parser.parse_args()


def copy_txt_files(source: Path, destination: Path) -> None:
    """Recursively copy .txt files, preserving relative paths."""
    if not source.is_dir():
        raise FileNotFoundError(f"Source directory not found: {source}")

    for txt_path in source.rglob("*.txt"):
        if not txt_path.is_file():
            continue

        rel_path = txt_path.relative_to(source)
        dest_path = destination / rel_path

        try:
            dest_path.parent.mkdir(parents=True, exist_ok=True)
            content = txt_path.read_text(encoding="utf-8")
            dest_path.write_text(content, encoding="utf-8")
        except FileNotFoundError as e:
            print(f"Missing source file: {e}", file=sys.stderr)
        except PermissionError as e:
            print(f"Permission denied: {e}", file=sys.stderr)
        except UnicodeDecodeError as e:
            print(f"Non-UTF-8 encoding in {txt_path}: {e}", file=sys.stderr)
        except OSError as e:
            print(f"OS error copying {txt_path} → {dest_path}: {e}", file=sys.stderr)


def main() -> None:
    args = parse_args()

    try:
        copy_txt_files(args.source, args.destination)
    except Exception as e:
        print(f"Unexpected error: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()
