#!/usr/bin/env python3
"""Recursively delete empty directories, walking bottom-up."""

from pathlib import Path
from argparse import ArgumentParser
import sys


def parse_args() -> tuple[Path, bool]:
    """Parse CLI arguments."""
    parser = ArgumentParser(
        description="Safely remove empty directories under a root path."
    )
    parser.add_argument(
        "root",
        type=Path,
        default=Path("/tmp/output"),
        nargs="?",
        help="Root directory to scan (default: /tmp/output)"
    )
    parser.add_argument(
        "--dry-run",
        action="store_true",
        help="Show what would be deleted without deleting"
    )
    args = parser.parse_args()
    if not args.root.exists():
        parser.error(f"Root path does not exist: {args.root}")
    if not args.root.is_dir():
        parser.error(f"Root path is not a directory: {args.root}")
    return args.root, args.dry_run


def main() -> None:
    root, dry_run = parse_args()
    deleted_count = 0

    # Walk bottom-up: remove children before parents
    for dirpath, dirnames, filenames in root.walk(top_down=False):
        # Skip root itself
        if dirpath == root:
            continue

        try:
            # Check if directory is truly empty (no files, no subdirs)
            if not any(dirpath.iterdir()):
                if dry_run:
                    print(f"[DRY-RUN] Would delete empty directory: {dirpath}")
                else:
                    dirpath.rmdir()
                    print(f"Deleted: {dirpath}")
                deleted_count += 1

        except PermissionError as e:
            print(f"Permission denied accessing '{dirpath}': {e}", file=sys.stderr)
            continue
        except OSError as e:
            print(f"Error rmdir '{dirpath}': {e}", file=sys.stderr)
            continue

    print(f"\nTotal directories {'(would be) ' if dry_run else ''}deleted: {deleted_count}")


if __name__ == "__main__":
    main()
