#!/usr/bin/env python3.12
"""List symlinks and their targets in a directory tree."""

import argparse
from pathlib import Path
from typing import List, Tuple


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="List symlinks and their targets, including broken ones."
    )
    parser.add_argument(
        "--dir",
        type=Path,
        default=Path("/mnt/agency-docs"),
        help="Root directory to scan (default: /mnt/agency-docs)",
    )
    return parser.parse_args()


def find_symlinks(directory: Path) -> List[Tuple[Path, str]]:
    """Recursively find all symlinks and resolve targets or report broken."""
    symlinks: List[Tuple[Path, str]] = []

    for path in directory.rglob("*"):
        try:
            if path.is_symlink():
                try:
                    # Try to resolve the target
                    resolved = path.resolve()
                    target_str = str(resolved)
                except (OSError, RuntimeError) as e:
                    # Broken symlink or other error during resolve
                    target_str = "BROKEN"
                symlinks.append((path, target_str))
        except PermissionError:
            # Skip directories we can’t scan
            continue

    return symlinks


def main() -> None:
    args = parse_args()

    if not args.dir.exists():
        raise FileNotFoundError(f"Directory not found: {args.dir}")

    symlinks = find_symlinks(args.dir)

    if not symlinks:
        print("No symlinks found.", flush=True)
        return

    print(f"Found {len(symlinks)} symlink(s):", flush=True)
    for path, target in sorted(symlinks):
        print(f"{path} → {target}", flush=True)


if __name__ == "__main__":
    main()
