#!/usr/bin/env python3.12
"""Count file extensions in a directory tree and report frequency."""

from pathlib import Path
from collections import Counter
import argparse
import sys


def count_extensions(root_path: Path) -> Counter:
    """Recursively count file extensions under root_path."""
    ext_counter: Counter = Counter()

    try:
        for item in root_path.rglob('*'):
            if item.is_file():
                ext = item.suffix.lstrip('.').lower() or 'no_extension'
                ext_counter[ext] += 1
    except PermissionError as e:
        print(f"⚠️ Permission denied accessing {e.filename}", file=sys.stderr)
    except OSError as e:
        print(f"⚠️ OS error while traversing {root_path}: {e}", file=sys.stderr)

    return ext_counter


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Count file extensions in a directory tree."
    )
    parser.add_argument(
        "--path",
        type=Path,
        default=Path("/mnt/agency-docs"),
        help="Root directory to scan (default: /mnt/agency-docs)"
    )
    parser.add_argument(
        "--top",
        type=int,
        default=10,
        help="Number of top extensions to display (default: 10)"
    )

    args = parser.parse_args()

    if not args.path.exists():
        print(f"Error: Path does not exist: {args.path}", file=sys.stderr)
        sys.exit(1)

    if not args.path.is_dir():
        print(f"Error: Path is not a directory: {args.path}", file=sys.stderr)
        sys.exit(1)

    counts = count_extensions(args.path)

    if not counts:
        print("No files found.")
        return

    print(f"\nFile extension counts (top {args.top}):\n")
    for ext, count in counts.most_common(args.top):
        print(f"{ext or '(none)':<12} {count:>6}")


if __name__ == "__main__":
    main()
