#!/usr/bin/env python3.12
"""Synchronize missing files from source to backup directory."""

from pathlib import Path
import argparse
import shutil
import sys
from typing import Set, List


def get_relative_paths(directory: Path) -> Set[str]:
    """Return set of relative paths (as strings) under directory."""
    paths: Set[str] = set()
    try:
        for item in directory.rglob('*'):
            if item.is_file():
                rel = item.relative_to(directory)
                paths.add(str(rel))
    except PermissionError as e:
        print(f"⚠️ Permission denied scanning {e.filename}", file=sys.stderr)
    except OSError as e:
        print(f"⚠️ OS error scanning {directory}: {e}", file=sys.stderr)
    return paths


def missing_files(source: Path, backup: Path) -> List[Path]:
    """Return list of source files missing in backup."""
    source_paths = get_relative_paths(source)
    backup_paths = get_relative_paths(backup)

    missing = []
    for rel_path in source_paths:
        source_file = source / rel_path
        backup_file = backup / rel_path
        if rel_path not in backup_paths:
            missing.append(source_file)

    return sorted(missing)


def copy_missing(source: Path, backup: Path, dry_run: bool = False) -> int:
    """Copy missing files from source to backup. Returns count copied."""
    missing = missing_files(source, backup)
    copied = 0

    for src_file in missing:
        dst_file = backup / src_file.relative_to(source)
        try:
            if dry_run:
                print(f"[dry-run] Would copy: {src_file}")
                copied += 1
            else:
                dst_file.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(src_file, dst_file)
                print(f"Copied: {src_file}")
                copied += 1
        except PermissionError as e:
            print(f"⚠️ Permission denied copying {src_file}: {e}", file=sys.stderr)
        except OSError as e:
            print(f"⚠️ OS error copying {src_file}: {e}", file=sys.stderr)

    return copied


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Copy files from source to backup if missing."
    )
    parser.add_argument(
        "--source",
        type=Path,
        default=Path("/mnt/agency-docs"),
        help="Source directory (default: /mnt/agency-docs)"
    )
    parser.add_argument(
        "--backup",
        type=Path,
        default=Path("/tmp/output/backup"),
        help="Backup directory (default: /tmp/output/backup)"
    )
    parser.add_argument(
        "--dry-run",
        action="store_true",
        help="Show what would be copied without copying"
    )

    args = parser.parse_args()

    if not args.source.exists():
        print(f"Error: Source directory does not exist: {args.source}", file=sys.stderr)
        sys.exit(1)

    if not args.source.is_dir():
        print(f"Error: Source path is not a directory: {args.source}", file=sys.stderr)
        sys.exit(1)

    if not args.backup.exists():
        try:
            args.backup.mkdir(parents=True, exist_ok=True)
        except PermissionError as e:
            print(f"Error: Cannot create backup directory {args.backup}: {e}", file=sys.stderr)
            sys.exit(1)

    print(f"\nComparing {args.source} → {args.backup}...\n")

    count = copy_missing(args.source, args.backup, args.dry_run)

    print(f"\n{count} file(s) {'would be copied' if args.dry_run else 'copied'}.")


if __name__ == "__main__":
    main()
